11→internal class ArchiveOperations(
12→    private val messagingController: MessagingController,
13→) {
14→    fun archiveThreads(messages: List<MessageReference>) {
15→        archiveByFolder("archiveThreads", messages) { account, folderId, messagesInFolder, archiveFolderId ->
16→            archiveThreads(account, folderId, messagesInFolder, archiveFolderId)
17→        }
18→    }
19→
20→    fun archiveMessages(messages: List<MessageReference>) {
21→        archiveByFolder("archiveMessages", messages) { account, folderId, messagesInFolder, archiveFolderId ->
22→            archiveMessages(account, folderId, messagesInFolder, archiveFolderId)
23→        }
24→    }
25→
26→    fun archiveMessage(message: MessageReference) {
27→        archiveMessages(listOf(message))
28→    }
29→
30→    private fun archiveByFolder(
31→        description: String,
32→        messages: List<MessageReference>,
33→        action: (account: Account, folderId: Long, messagesInFolder: List<LocalMessage>, archiveFolderId: Long) -> Unit,
34→    ) {
35→        actOnMessagesGroupedByAccountAndFolder(messages) { account, messageFolder, messagesInFolder ->
36→            val sourceFolderId = messageFolder.databaseId
37→            when (val archiveFolderId = account.archiveFolderId) {
38→                null -> {
39→                    Timber.v("No archive folder configured for account %s", account)
40→                }
41→
42→                sourceFolderId -> {
43→                    Timber.v("Skipping messages already in archive folder")
44→                }
45→
46→                else -> {
47→                    messagingController.suppressMessages(account, messagesInFolder)
48→                    messagingController.putBackground(description, null) {
49→                        action(account, sourceFolderId, messagesInFolder, archiveFolderId)
50→                    }
51→                }
52→            }
53→        }
54→    }
55→
56→    private fun archiveThreads(
57→        account: Account,
58→        sourceFolderId: Long,
59→        messages: List<LocalMessage>,
60→        archiveFolderId: Long,
61→    ) {
62→        val messagesInThreads = messagingController.collectMessagesInThreads(account, messages)
63→        archiveMessages(account, sourceFolderId, messagesInThreads, archiveFolderId)
64→    }
65→
66→    private fun archiveMessages(
67→        account: Account,
68→        sourceFolderId: Long,
69→        messages: List<LocalMessage>,
70→        archiveFolderId: Long,
71→    ) {
72→        messagingController.moveOrCopyMessageSynchronous(
73→            account,
74→            sourceFolderId,
75→            messages,
76→            archiveFolderId,
77→            MoveOrCopyFlavor.MOVE,
78→        )
79→    }
80→
81→    private fun actOnMessagesGroupedByAccountAndFolder(
82→        messages: List<MessageReference>,
83→        block: (account: Account, messageFolder: LocalFolder, messages: List<LocalMessage>) -> Unit,
84→    ) {
85→        val actor = MessageActor { account, messageFolder, messagesInFolder ->
86→            block(account, messageFolder, messagesInFolder)
87→        }
88→
89→        messagingController.actOnMessagesGroupedByAccountAndFolder(messages, actor)
90→    }
91→}
